1	/**
2	 * Background processing for uploaded files.
3	 *
4	 * Happy path (local / self-hosted): run Noosphere's Typer CLI
5	 * (`python -m noosphere ingest` + `synthesize`), streaming stdout/stderr
6	 * into `Upload.processLog` so the UI can show live progress.
7	 *
8	 * Serverless path (Vercel): Python isn't available. Previously this code
9	 * just `spawn`'d `python3` and the user saw `Error: spawn python3 ENOENT`
10	 * in the process log (see {@link NOOSPHERE_UNAVAILABLE_MESSAGE}). Now we
11	 * detect that case up front, mark the upload as `queued_offline` with an
12	 * explanatory log, and let the user run the CLI locally against the shared
13	 * Postgres to finish the job.
14	 */
15	
16	import { readFile } from "fs/promises";
17	import { join } from "path";
18	import { db } from "./db";
19	import {
20	  runNoospherePython,
21	  isNoosphereLikelyUnavailable,
22	  NOOSPHERE_UNAVAILABLE_MESSAGE,
23	} from "./pythonRuntime";
24	
25	const NOOSPHERE_PYTHON = process.env.NOOSPHERE_PYTHON || "python3";
26	/** Directory containing the `noosphere` Python package (parent of `noosphere/`). */
27	const NOOSPHERE_SRC_ROOT =
28	  process.env.NOOSPHERE_SRC_ROOT || join(process.cwd(), "..", "noosphere");
29	const OPENAI_API_KEY = process.env.OPENAI_API_KEY || "";
30	
31	async function appendLog(uploadId: string, chunk: string) {
32	  const prev = await db.upload.findUnique({
33	    where: { id: uploadId },
34	    select: { processLog: true },
35	  });
36	  const next = (prev?.processLog || "") + chunk;
37	  await db.upload.update({
38	    where: { id: uploadId },
39	    data: { processLog: next.slice(-200_000) },
40	  });
41	}
42	
43	async function extractText(filePath: string, mimeType: string, originalName: string): Promise<string | null> {
44	  if (
45	    mimeType === "text/plain" ||
46	    mimeType === "text/markdown" ||
47	    mimeType === "text/vtt" ||
48	    mimeType === "application/x-ndjson" ||
49	    originalName.match(/\.(txt|md|markdown|vtt|jsonl)$/i)
50	  ) {
51	    // `filePath` may be a real path (self-hosted) or a marker like
52	    // `inline:uuid.txt` (Vercel — see api/upload/route.ts). Only read from
53	    // disk when it looks like an actual path.
54	    if (filePath.startsWith("inline:")) return null;
55	    return readFile(filePath, "utf-8");
56	  }
57	  return null;
58	}
59	
60	async function transcribeAudio(filePath: string, originalName: string): Promise<string | null> {
61	  if (!OPENAI_API_KEY) return null;
62	  if (filePath.startsWith("inline:")) return null;
63	  try {
64	    const { default: OpenAI } = await import("openai");
65	    const openai = new OpenAI({ apiKey: OPENAI_API_KEY });
66	    const fileBuffer = await readFile(filePath);
67	    const file = new File([fileBuffer], originalName, { type: "audio/mpeg" });
68	    const transcription = await openai.audio.transcriptions.create({
69	      model: "whisper-1",
70	      file,
71	      response_format: "text",
72	    });
73	    return typeof transcription === "string"
74	      ? transcription
75	      : (transcription as { text?: string }).text || null;
76	  } catch {
77	    return null;
78	  }
79	}
80	
81	/**
82	 * Background job: mark processing → (try to) run CLI ingest + synthesize
83	 * → update counts / status. When Python isn't reachable we still persist
84	 * textContent to Postgres and set status to `queued_offline` so the user
85	 * can find the upload in the UI and run the CLI locally.
86	 */
87	export async function processUpload(uploadId: string): Promise<void> {
88	  const upload = await db.upload.findUnique({
89	    where: { id: uploadId },
90	    include: { founder: true },
91	  });
92	
93	  if (!upload) {
94	    console.error(`Upload ${uploadId} not found`);
95	    return;
96	  }
97	
98	  try {
99	    // APPEND to whatever processLog already exists (the upload handler
100	    // wrote an initial header + auto-process dispatch note before this
101	    // job started). Previously we overwrote the field, which nuked the
102	    // dispatch status message and made it look like auto-processing
103	    // wasn't configured. `appendLog` is read-then-write so it preserves
104	    // prior content.
105	    await appendLog(uploadId, "— Starting local Noosphere ingest —\n");
106	    await db.upload.update({
107	      where: { id: uploadId },
108	      data: { status: "processing" },
109	    });
110	
111	    let textContent = upload.textContent;
112	    if (!textContent) {
113	      const isAudio = upload.mimeType.startsWith("audio/");
114	      if (isAudio) {
115	        textContent = await transcribeAudio(upload.filePath, upload.originalName);
116	      } else {
117	        textContent = await extractText(upload.filePath, upload.mimeType, upload.originalName);
118	      }
119	      if (textContent) {
120	        await db.upload.update({ where: { id: uploadId }, data: { textContent } });
121	      }
122	    }
123	
124	    // ────────────────────────────────────────────────────────────────────
125	    // Serverless / Python-less hosts: don't even try to spawn. The upload
126	    // row is already persisted (textContent is in Postgres for text-like
127	    // files), so mark it as queued for offline processing and return.
128	    //
129	    // Two flavors:
130	    //   (a) auto-processing via GitHub Actions IS configured — a separate
131	    //       webhook + cron workflow will pick up `queued_offline` rows.
132	    //       We write a short "handed off" note pointing to the Actions
133	    //       run and return. The 10-min cron will turn this into
134	    //       `ingested` within minutes.
135	    //   (b) no auto-processing — fall back to the old "run it yourself"
136	    //       instructions.
137	    // ────────────────────────────────────────────────────────────────────
138	    if (isNoosphereLikelyUnavailable()) {
139	      const autoProcessRepo = process.env.GITHUB_DISPATCH_REPO || "mrquintin/mqtheseuswork";
140	      const autoProcessEnabled = Boolean(process.env.GITHUB_DISPATCH_TOKEN);
141	
142	      if (autoProcessEnabled) {
143	        await appendLog(
144	          uploadId,
145	          `\n— Python not available in this runtime —\n` +
146	            `Upload handed off to GitHub Actions. Watch the run live at\n` +
147	            `  https://github.com/${autoProcessRepo}/actions/workflows/noosphere-process-uploads.yml\n` +
148	            `Results (conclusions, contradictions, questions) appear at\n` +
149	            `/conclusions, /contradictions, /open-questions, /research\n` +
150	            `within 1–3 minutes. The 10-minute scheduled sweep also\n` +

