1	/**
2	 * Minimal client for Supabase Storage via its REST API.
3	 *
4	 * We avoid adding `@supabase/supabase-js` because we only need two
5	 * calls — `createSignedUploadUrl` and `upload` — and pulling in the
6	 * whole client library would inflate the serverless bundle for a
7	 * feature that's gated behind env config anyway. The Storage REST API
8	 * is stable and well-documented at
9	 * https://supabase.com/docs/guides/storage.
10	 *
11	 * Env configuration (both must be set on Vercel for audio uploads
12	 * to be playable — the blog gracefully degrades to text-only when
13	 * they're missing):
14	 *
15	 *   SUPABASE_URL                 e.g. https://ltuglowgkaircxgjcjvs.supabase.co
16	 *   SUPABASE_SERVICE_ROLE_KEY    server-side-only key; never ship to the
17	 *                                 browser. Creates + signs upload URLs.
18	 *   SUPABASE_AUDIO_BUCKET        bucket name (default: "audio"). MUST be
19	 *                                 created in the Supabase dashboard and
20	 *                                 marked public-read.
21	 */
22	
23	const DEFAULT_BUCKET = "audio";
24	
25	/** True when both env vars are set. Used by routes to decide whether
26	 *  to offer the signed-URL flow or degrade gracefully. */
27	export function isAudioStorageConfigured(): boolean {
28	  return Boolean(
29	    process.env.SUPABASE_URL && process.env.SUPABASE_SERVICE_ROLE_KEY,
30	  );
31	}
32	
33	export function getAudioBucket(): string {
34	  return process.env.SUPABASE_AUDIO_BUCKET || DEFAULT_BUCKET;
35	}
36	
37	function getConfig(): { url: string; key: string; bucket: string } | null {
38	  const url = process.env.SUPABASE_URL;
39	  const key = process.env.SUPABASE_SERVICE_ROLE_KEY;
40	  if (!url || !key) return null;
41	  return { url: url.replace(/\/+$/, ""), key, bucket: getAudioBucket() };
42	}
43	
44	/** Public CDN URL for an object. Constructed from the bucket + path,
45	 *  so this doesn't need a network call — safe to call even if the
46	 *  storage service is unreachable. */
47	export function getPublicAudioUrl(objectPath: string): string | null {
48	  const cfg = getConfig();
49	  if (!cfg) return null;
50	  return `${cfg.url}/storage/v1/object/public/${encodeURIComponent(
51	    cfg.bucket,
52	  )}/${objectPath.split("/").map(encodeURIComponent).join("/")}`;
53	}
54	
55	export interface SignedUploadHandle {
56	  /** One-shot PUT URL the client uses directly from the browser. */
57	  signedUrl: string;
58	  /** Opaque token Supabase returns — the client must include it as
59	   *  `Authorization: Bearer <token>` on the PUT. Newer SDK versions
60	   *  bake this into the URL; we forward both for compat. */
61	  token: string;
62	  /** Path inside the bucket, e.g. "cmo4sd…/podcast.mp3". */
63	  path: string;
64	  /** Final public URL after the upload completes. */
65	  publicUrl: string;
66	}
67	
68	/**
69	 * Ask Supabase for a signed URL the client can PUT to directly, so
70	 * we don't send large audio through Vercel's 4.4 MB serverless body
71	 * limit. Returns null when Storage isn't configured so callers can
72	 * fall back to the "small files only" path without special-casing.
73	 */
74	export async function createSignedAudioUploadUrl(
75	  objectPath: string,
76	): Promise<SignedUploadHandle | null> {
77	  const cfg = getConfig();
78	  if (!cfg) return null;
79	
80	  const endpoint = `${cfg.url}/storage/v1/object/upload/sign/${encodeURIComponent(
81	    cfg.bucket,
82	  )}/${objectPath.split("/").map(encodeURIComponent).join("/")}`;
83	
84	  const res = await fetch(endpoint, {
85	    method: "POST",
86	    headers: {
87	      Authorization: `Bearer ${cfg.key}`,
88	      apikey: cfg.key,
89	      "Content-Type": "application/json",
90	    },
91	    body: JSON.stringify({}),
92	  });
93	  if (!res.ok) {
94	    const errBody = await res.text().catch(() => "<unreadable>");
95	    throw new Error(
96	      `Supabase Storage sign failed: HTTP ${res.status} — ${errBody.slice(0, 240)}`,
97	    );
98	  }
99	  const data = (await res.json()) as { url?: string; token?: string };
100	  if (!data.url) {
101	    throw new Error("Supabase Storage sign returned no URL in response.");
102	  }
103	  // Supabase's sign endpoint returns a URL *relative to the Storage
104	  // service*, i.e. "/object/upload/sign/<bucket>/<path>?token=<jwt>".
105	  // SUPABASE_URL is the project origin ("https://xxx.supabase.co"),
106	  // NOT the Storage service root ("…/storage/v1"). Naively doing
107	  // `${cfg.url}${data.url}` produces
108	  //   https://xxx.supabase.co/object/upload/sign/…
109	  // which isn't routed to Storage at all — the browser PUT fails
110	  // as an opaque "Failed to fetch" / CORS error after a long wait.
111	  //
112	  // Fix: inject "/storage/v1" when the response is relative. Handle
113	  // all three shapes defensively in case Supabase changes the API:
114	  //   - absolute URL                    → use as-is
115	  //   - starts with "/storage/v1/…"     → prepend origin only
116	  //   - starts with "/object/…"         → prepend origin + "/storage/v1"
117	  let signedUrl: string;
118	  if (data.url.startsWith("http://") || data.url.startsWith("https://")) {
119	    signedUrl = data.url;
120	  } else {
121	    const leading = data.url.startsWith("/") ? data.url : `/${data.url}`;
122	    signedUrl = leading.startsWith("/storage/v1/")
123	      ? `${cfg.url}${leading}`
124	      : `${cfg.url}/storage/v1${leading}`;
125	  }
126	
127	  return {
128	    signedUrl,
129	    token: data.token || "",
130	    path: objectPath,
131	    publicUrl: getPublicAudioUrl(objectPath)!,
132	  };
133	}
134	
135	/**
136	 * Server-side upload for the small-audio path (files that already
137	 * fit in the Vercel request body). We still route them through
138	 * Storage so the blog post has a persistent URL.
139	 */
140	export async function uploadAudioBuffer(
141	  objectPath: string,
142	  buffer: Uint8Array,
143	  contentType: string,
144	): Promise<string | null> {
145	  const cfg = getConfig();
146	  if (!cfg) return null;
147	
148	  const endpoint = `${cfg.url}/storage/v1/object/${encodeURIComponent(
149	    cfg.bucket,
150	  )}/${objectPath.split("/").map(encodeURIComponent).join("/")}`;
151	
152	  // Wrap the Uint8Array in a Blob. TS-strict with lib.dom.d.ts rejects
153	  // a `Uint8Array<ArrayBufferLike>` as a BlobPart because the buffer
154	  // could in principle be a SharedArrayBuffer (it isn't, but the type
155	  // system doesn't know). We copy into a plain ArrayBuffer first, then
156	  // wrap — adds one allocation, preserves correctness, satisfies TS.
157	  const ab = new ArrayBuffer(buffer.byteLength);
158	  new Uint8Array(ab).set(buffer);
159	  const body = new Blob([ab], {
160	    type: contentType || "application/octet-stream",
161	  });
162	
163	  const res = await fetch(endpoint, {
164	    method: "POST",
165	    headers: {
166	      Authorization: `Bearer ${cfg.key}`,
167	      apikey: cfg.key,
168	      "Content-Type": contentType || "application/octet-stream",
169	      // Upsert so re-uploading the same path replaces instead of 409.
170	      // The object path is `<uploadId>/<filename>` which is unique
171	      // per upload, so this only matters for retries.
172	      "x-upsert": "true",
173	    },
174	    body,
175	  });
176	  if (!res.ok) {
177	    const errBody = await res.text().catch(() => "<unreadable>");
178	    throw new Error(
179	      `Supabase Storage upload failed: HTTP ${res.status} — ${errBody.slice(0, 240)}`,
180	    );
181	  }
182	  return getPublicAudioUrl(objectPath);
183	}
184	
185	/**
186	 * Verify an upload actually landed in Storage. Called by the finalize
187	 * endpoint before we flip `Upload.audioUrl` — otherwise a client
188	 * could POST to /finalize without actually uploading the audio and
189	 * we'd attach a 404 URL to a blog post.
190	 */
191	export async function audioObjectExists(objectPath: string): Promise<boolean> {
192	  const cfg = getConfig();
193	  if (!cfg) return false;
194	
195	  const endpoint = `${cfg.url}/storage/v1/object/info/${encodeURIComponent(
196	    cfg.bucket,
197	  )}/${objectPath.split("/").map(encodeURIComponent).join("/")}`;
198	
199	  const res = await fetch(endpoint, {
200	    method: "GET",
201	    headers: {
202	      Authorization: `Bearer ${cfg.key}`,
203	      apikey: cfg.key,
204	    },
205	  });
206	  return res.ok;
207	}
208	
209	/**
210	 * Best-effort read of the configured bucket's file-size limit, in bytes.
211	 *
212	 * Why this exists:
213	 * - Codex has its own app-level upload cap (`MAX_UPLOAD_BYTES`), but
214	 *   Supabase buckets can enforce a *lower* per-file cap (often 50 MB by
215	 *   default).
216	 * - When the bucket cap is lower, browser PUTs can fail with opaque
217	 *   "network error" symptoms after waiting.
218	 *
219	 * The prepare route can call this to fail fast with an actionable 413
220	 * before the browser starts a long upload.
221	 */
222	export async function getAudioBucketFileSizeLimitBytes(): Promise<number | null> {
223	  const cfg = getConfig();
224	  if (!cfg) return null;
225	
226	  const endpoint = `${cfg.url}/storage/v1/bucket/${encodeURIComponent(
227	    cfg.bucket,
228	  )}`;
229	
230	  const res = await fetch(endpoint, {
231	    method: "GET",
232	    headers: {
233	      Authorization: `Bearer ${cfg.key}`,
234	      apikey: cfg.key,
235	    },
236	  });
237	  if (!res.ok) return null;
238	
239	  const data = (await res.json().catch(() => null)) as
240	    | { file_size_limit?: number | string | null }
241	    | null;
242	  if (!data) return null;
243	  const raw = data.file_size_limit;
244	  if (raw === null || raw === undefined || raw === "") return null;
245	  const n = typeof raw === "number" ? raw : Number(raw);
246	  if (!Number.isFinite(n) || n <= 0) return null;
247	  return Math.floor(n);
248	}
249	
250	/**
251	 * Ensure the audio bucket is configured to accept at least
252	 * `requiredBytes` per file. If the current cap is already high
253	 * enough, this is a no-op. If the cap is lower (or unset — see the
254	 * `null` trap below), we PATCH the bucket to raise the cap to
255	 * `max(requiredBytes, DEFAULT_TARGET)` in one service-role-authed
256	 * request.
257	 *
258	 * Why this is needed
259	 * ------------------
260	 * A freshly-created Supabase bucket has `file_size_limit = null`,
261	 * which the docs describe as "no per-bucket cap" but in practice
262	 * means "inherits the project's plan-level per-file ceiling". On the
263	 * free tier that ceiling is 50 MB; on Pro it's 50 GB. Either way
264	 * `null` is NOT the same as "unlimited", and a size-preflight that
265	 * reads `null` and skips the check will let an oversized upload
266	 * start and then fail with an opaque 413 halfway through the PUT.
267	 *
268	 * Raising the cap via the admin API turns `null` into an explicit
269	 * number we control, so subsequent preflights can see it AND the
270	 * Supabase-side check won't reject the PUT until it hits the actual
271	 * plan-level ceiling.
272	 *
273	 * Failure modes handled:
274	 * - `cfg` missing → `{ ok: false, reason: "unconfigured" }`.
275	 * - GET on bucket fails (404, network, etc.) → treat current cap as
276	 *   unknown and attempt a raise anyway.
277	 * - PATCH rejected (e.g. plan-level hard ceiling hit) → `{ ok: false,
